-- 删除租户时级联删除用户，并修复所有引用 users 的非 CASCADE 外键

-- 1) 将 users.tenant_id 从 SET NULL 改为 CASCADE
ALTER TABLE users DROP CONSTRAINT fk_users_tenant;
ALTER TABLE users ADD CONSTRAINT fk_users_tenant
    FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE;

-- 2) 将 creator_id 的 SET NULL 改为 CASCADE
DO $$ BEGIN ALTER TABLE scenarios        DROP CONSTRAINT IF EXISTS fk_scenarios_creator;        ALTER TABLE scenarios        ADD CONSTRAINT fk_scenarios_creator         FOREIGN KEY (creator_id) REFERENCES users(id) ON DELETE CASCADE; EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE knowledge_points DROP CONSTRAINT IF EXISTS fk_knowledge_points_creator; ALTER TABLE knowledge_points ADD CONSTRAINT fk_knowledge_points_creator  FOREIGN KEY (creator_id) REFERENCES users(id) ON DELETE CASCADE; EXCEPTION WHEN duplicate_object THEN NULL; END $$;
