DO $$ BEGIN ALTER TABLE exam_usages      DROP CONSTRAINT IF EXISTS fk_exam_usages_creator;      ALTER TABLE exam_usages      ADD CONSTRAINT fk_exam_usages_creator       FOREIGN KEY (creator_id) REFERENCES users(id) ON DELETE CASCADE; EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN ALTER TABLE courses          DROP CONSTRAINT IF EXISTS fk_courses_creator;          ALTER TABLE courses          ADD CONSTRAINT fk_courses_creator           FOREIGN KEY (creator_id) REFERENCES users(id) ON DELETE CASCADE; EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- 3) 评测/业务表中引用 users 但没有 ON DELETE 动作的外键 → 改为 CASCADE
DO $$ BEGIN ALTER TABLE scene_evaluation_results       DROP CONSTRAINT IF EXISTS scene_evaluation_results_evaluatee_id_fkey;  ALTER TABLE scene_evaluation_results       ADD CONSTRAINT scene_evaluation_results_evaluatee_id_fkey  FOREIGN KEY (evaluatee_id) REFERENCES users(id) ON DELETE CASCADE; EXCEPTION WHEN duplicate_object THEN NULL; END $$;
